import json
from os import path
import pickle



class PreferencesManager:
	def __init__(self):
		self._preferences = {}

	@property
	def preferences(self) -> dict:
		return self._preferences
	
	def getPreference(self, preferenceName) -> Any:
		return self.preferences[preferenceName]
	
	def setPreference(self, preferenceName:str , preferenceValue):
		
		if not isinstance(preferenceValue, dict):
			self._preferences[preferenceName] =  preferenceValue
		else :
			self.preferences[preferenceName].update(preferenceValue)

	def dumpToFile(self):
		with open(path.join(path.dirname(__file__), 'preference'), mode='wb') as f:
			pickle.dump(self._preferences, file=f)
	def loadFromFile():
		with open(path.join(path.dirname(__file__), 'preference'),mode = 'rb' ) as  f :
				return pickle.load(f)